#!/usr/bin/env python3
# apply_oz_portraits.py — replace Wizard of Oz character portraits with new sheet art.
# Overwrites existing indices a79-a92 in assets/assets.json with RAW base64 JPEG.
# (China Princess a134 is NOT on this sheet and is left untouched; Winkie Soldier has
#  no card yet and is omitted.) The game source does NOT change.
# Usage from repo root:  python3 apply_oz_portraits.py  &&  python3 build.py
import json, os, sys

root=os.path.dirname(os.path.abspath(__file__)); AJ=os.path.join(root,"assets","assets.json")
NEW={
  "a79": "",
  "a80": "",
  "a81": "",
  "a82": "",
  "a83": "",
  "a84": "",
  "a85": "",
  "a86": "",
  "a87": "",
  "a88": "",
  "a89": "",
  "a90": "",
  "a91": "",
  "a92": "",
}

if not os.path.exists(AJ): sys.exit("[apply] assets/assets.json not found — run from repo root.")
a=json.load(open(AJ))
def raw_only(v):
    i=v.find('base64,'); return v[i+7:] if i!=-1 else v
ch=[]
for k,v in NEW.items():
    nv=raw_only(v)
    if a.get(k)!=nv: a[k]=nv; ch.append(k)
json.dump(a,open(AJ,"w"))
print(f"[apply] oz portraits -> updated {len(ch)}: {sorted(ch,key=lambda x:int(x[1:])) or '(none)'}")
print("[apply] done. Next: python3 build.py")
